import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MyChart } from '../../../../../includes';
import { monthLabels } from '../../../../../../utils';
import { hirUtil } from '../../../../utils';
import { hirFamilyActions } from '../../../actions';
const style = theme => ({
    root: {
        
    }
})
class _HIRFamilyYearlyAppointments extends Component {
    static getData(members, year, dispatch, callback){
        return new Promise((resolve, reject)=>{
            hirFamilyActions.getFamilyYearlyAppointments(members, year, (done, result, message)=>{
                if(done){
                    resolve(result);
                    if(callback) callback(null, result);
                }else{
                    reject(message);
                    if(callback) callback(message);
                }
            })(dispatch);
        });
    }
    colors = [
        "#673ab7", "#ff5722", "#e91e63", 
            "#9c27b0", "#3f51b5","#795548", "#9e9e9e", 
            "#607d8b","#4caf50","#009688","#8bc34a",
    ]
    adjustMultipleData(data, aggregateName){
        const {members} = this.props;
        let mainData = {};
        let total = {};
        if(data) for (let i = 0; i < data.length; i++) {
            const {patientId, year, month} = data[i]._id;
            if(mainData[patientId]){
                mainData[patientId].push({_id : {month}, [aggregateName]: data[i][aggregateName]});
            }else{
                mainData[patientId] = [{_id : {month}, [aggregateName]: data[i][aggregateName]}];
            }

            if(total[month]) total[month]+=data[i][aggregateName];
            else total[month] = data[i][aggregateName];
        }
        const finalData = [];
        if(mainData){
            for (const patientId in mainData) {
                if (mainData.hasOwnProperty(patientId)) {
                    const set = mainData[patientId];
                    let name ;
                    if(members){
                        const patient = members.find(item=>item._id === parseInt(patientId));
                        if(patient && patient.myProfile)
                            name = (patient.myProfile.firstName ? patient.myProfile.firstName : null) + 
                            ", " +patient.myProfile.lastName                                 
                    }
                    finalData.push({
                        label: name,
                        data : this.deriveMonthlyData(set, aggregateName),                                
                        backgroundColor : "transparent",
                        borderColor : this.colors[finalData.length],
                    })
                }
            }
        }
        finalData.push({
            label : "Total",
            data : this.deriveTotalData(total),
            backgroundColor : "transparent",
            borderColor : "black",
        })
        return finalData;
    }
    deriveMonthlyData(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            const value = data.find(item=>item._id.month==i+1);
            if(value){
                returnData.push(value[valueName]);
            }else returnData.push(0);
        }
        return returnData;
    }
    deriveTotalData(data){
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            if(data[i + 1]){
                returnData.push(data[i+1]);
            }else returnData.push(0);
        }
        return returnData;
    }
    render() {
        const {classes, data, year} = this.props;
        return (
            <MyChart
                canvasId="patientYearlyAppointments"
                title={"Monthly Appointments "+year}
                labels={monthLabels}
                datasets={this.adjustMultipleData(data, "count")}
            />
        );
    }
}
_HIRFamilyYearlyAppointments.propTypes = {
    classes : PropTypes.object.isRequired,
    members : PropTypes.array,
};
export const HIRFamilyYearlyAppointments = withStyles(style)(_HIRFamilyYearlyAppointments);