import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import classNames  from 'classnames';
import { headerActions, headerStrings, breadCrumbActions, StageHeaderPlane, MyDialog } from '../../../includes';
import { hirRouteNames } from '../../routeNames';
import HIRPatientList from '../../HIRPatients/HIRPatientList/HIRPatientList';
import { hirFamilyActions } from '../actions';
import { HIRButton } from '../../Includes';
import { IconButton, CircularProgress, Menu, MenuItem, Button, Typography } from '@material-ui/core';
import { Refresh } from '@material-ui/icons';
import { HIRNewPatient } from '../../HIRPatients/HIRNewPatient';
import { HIRFindPatient } from '../../HIRPatients';
import { appActions, alertAction } from '../../../../actions';
import { hirFamilyStrings } from '../config';
import { HIRFamilyStatistics } from './HIRFamilyStatistics';


const style = theme => ({
    root: {
    },
    headerBtn : {
        marginLeft : 5,
    },
    headerBtnAnimation : {
        animationName : "$glowing",
        animationDuration : "1s",
        animationTimingFunction : "linear",
        animationIterationCount :"infinite",
    },
    blinkingBtn : {

    },
    '@keyframes glowing' : {
        from : {
            background : "#2ba805",
            boxShadow : "0 0 5px #2ba805",
        },
        to : {
            background : "#49e819",
            boxShadow : "0 0 5px #49e819",
        },
    },
    familyId : {
        textAlign : "center",
        fontWeight : "bold",
        color : theme.colors.primary1
    }
})
class _HIRFamilyView extends Component {
    constructor(props) {
        super(props);
        this.familyId = parseInt(props.match.params.id);
        this.family = props.location.state;
        console.log(this.family);
        this.state = {
            members : null,
            patientClicked : null,
            refreshing : false,
            newFamilyMemberMenu : false,
            menuAnchor : null,
            listMenuAnchorEl : null,
            addNewPatientDialog : false,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "FAMILY - " + this.family.name,
            [headerStrings.backButtonAction] : ()=>props.history.replace(hirRouteNames.families)
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Families", pathname : hirRouteNames.families},
            {name : this.family.name, pathname : hirRouteNames.familiesView_+this.familyId}
        ])(dispatch);
    }
    componentDidMount() {
        this.getFamily();
    }
    
    getFamily(callback) {
        const {dispatch} = this.props;
        hirFamilyActions.getAFamily(this.familyId, (done, result)=>{
            if(done) {
                this.family = result;
                this.setState({memberIds : result.members, members : result.familyMembers});
            }
        })(dispatch);
    }
    saveButton = () => {
        const {newFamilyMembers} = this.props;
        const {classes} = this.props;
        return newFamilyMembers && newFamilyMembers[this.familyId] && 
            newFamilyMembers[this.familyId].length > 0 ?  <HIRButton
                type="highlight" 
                classes={{btn : classNames(classes.headerBtn, classes.headerBtnAnimation)}}
                onClick={this.saveNewMembersWarning.bind(this)}>
                    Save
                </HIRButton> : null
    }
    saveNewMembersWarning(){
        const {[hirFamilyStrings.newFamilyMembers] : addedMembers} = this.props;
        const newFamilyMembers = addedMembers[this.familyId];
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "You are about to add " + newFamilyMembers.length + " new members into this family.\nDo you want to continue?",
            [
                <Button key="saveNewFamilies" onClick={this.addNewPatient.bind(this)}>Continue</Button>
            ]
        )(dispatch);
    }
    addNewPatient(){
        const {dispatch, [hirFamilyStrings.newFamilyMembers] : addedMembers} = this.props;
        appActions.closeSnackDialog()(dispatch);
        const newFamilyMembers = addedMembers[this.familyId];
        const patientIds = this.family.members || [];
        const newPatientIds = [];
        for (let i = 0; i < newFamilyMembers.length; i++) {
            const element = newFamilyMembers[i];
            patientIds.push(element._id);
            newPatientIds.push(element._id);
        }
        if(patientIds.length > 0){
            hirFamilyActions.addFamilyMembers(
                this.familyId, patientIds, newPatientIds, newFamilyMembers,
                (done, result)=>{
                    if(done){
                        this.family.members = patientIds;
                        this.props.location.state = this.family;
                        this.refresh()
                    }
                }
            )(dispatch);
        }
    }
    deleteFamilyButton(){
        const {classes} = this.props;
        return <HIRButton
            classes={{btn : classes.headerBtn}}
            type="secondary" 
            onClick={this.deleteFamilyWarning.bind(this)}>
                Delete this family
            </HIRButton>            
    }
    deleteFamilyWarning(){
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure want to delete " +this.family.name+"'s family?",
            [<Button key="deletefamily" onClick={this.deleteFamily.bind(this)}>Delete</Button>]
        )(dispatch);
    }
    deleteFamily(){
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirFamilyActions.deleteFamily(this.familyId, (done)=>{
            if(done){
                this.props.history.goBack();
            }
        })(dispatch);
    }
    newButton = () => {
        const {menuAnchor} = this.state;
        return <div>
            <HIRButton
                type="primary" 
                onClick={this.openNewMemberMenu.bind(this)}>
                    Add Members
                </HIRButton>
            <Menu 
                anchorEl={menuAnchor}
                open={Boolean(menuAnchor)}
                onClose={()=>this.setState({menuAnchor : null})}
                >
                <MenuItem 
                    onClick={()=>this.setState({
                        addNewPatientDialog : true, 
                        addType : "new",
                        menuAnchor : null
                    })}>New Patient</MenuItem>
                <MenuItem 
                    onClick={()=>this.setState({
                        addNewPatientDialog : true, 
                        menuAnchor : null,
                        addType : "existing"
                    })}>Existing Patient</MenuItem>
            </Menu>
        </div>
    }
    openNewMemberMenu(e){
        const target = e.target;
        this.setState(state=>({menuAnchor : state.menuAnchor ? null : target}));
    }
    refreshButton = () => {
        const {refreshing} = this.state;
        return <IconButton 
            disabled={refreshing}
            onClick={this.refresh.bind(this)}>
            {refreshing ? <CircularProgress style={{width : 25, height : 25}}/> : <Refresh/>}
        </IconButton>
    }
    refresh(){
        const {dispatch} = this.props;
        this.setState({refreshing : true});
        hirFamilyActions.setNewFamilyMembers(this.familyId, null)(dispatch);
        this.getFamily((done, result)=>{
            this.setState({refreshing : false});
        })
    }
    handleSelectedPatients = patient => () => {
        const {dispatch, [hirFamilyStrings.newFamilyMembers] : addedMembers} = this.props;
        const newFamilyMembers = addedMembers ? addedMembers[this.familyId] : null;
        const {members} = this.state;
        if((members && members.findIndex(item => item._id === patient._id) === -1) &&
        (newFamilyMembers && newFamilyMembers.findIndex(item=>item._id === patient._id)=== -1) ||
        !members || !newFamilyMembers){
            this.setState({addNewPatientDialog : false});
            hirFamilyActions.setNewFamilyMembers(
                this.familyId,
                newFamilyMembers && newFamilyMembers[this.familyId] ? 
                    [...newFamilyMembers, patient] : 
                    [patient]
            )(dispatch);
        }else {
            appActions.showSnackbar(
                alertAction.error("Patient is already a member of this family")
            )(dispatch);
        }
    }
    patientListRowAction = row => e => {
        const target = e.currentTarget;
        this.setState(state=>({listMenuAnchorEl : state.listMenuAnchorEl ? null : target, patientClicked : row}))
    }
    handlePatientMenuItems = option => e => {
        const {patientClicked} = this.state;
        this.setState({listMenuAnchorEl : null});
        if(option === "remove"){
            const {[hirFamilyStrings.newFamilyMembers] : addedMembers, dispatch} = this.props;
            const newFamilyMembers = addedMembers ? addedMembers[this.familyId] : null;
            if(newFamilyMembers){
                const index = newFamilyMembers.find(item=>item._id === patientClicked._id);
                if(index !== -1){
                    newFamilyMembers.splice(index, 1);
                    this.setState({listMenuAnchorEl : null});
                    hirFamilyActions.setNewFamilyMembers(this.familyId, newFamilyMembers)(dispatch);
                }
            }else{
                appActions.showSnackDialog(
                    "Are you sure you want to delete this patient from the family?",
                    [<Button key="deleteFamilyMember" onClick={this.deleteFamilyMember(patientClicked._id)}>Delete</Button>]
                )(dispatch);
            }
        }else{
            this.props.history.push({pathname : hirRouteNames.patientView_+patientClicked._id, state : patientClicked})
        }
    }
    deleteFamilyMember = (patientId) => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirFamilyActions.deleteFamilyMember(this.familyId, patientId, done=>{
            if(done) {
                this.getFamily();
            }
        })(dispatch);
    }
    createAndNewPatient(data, context){
        const {dispatch} = this.props;
        hirFamilyActions.createPatient(data, (done, result)=>{
            if(context) context.setState({loading : false});
            if(done){
                this.handleSelectedPatients(result)();
                this.setState({addNewPatientDialog : false, addType : null});
            }
        })(dispatch);
    }
    render() {
        const {classes, [hirFamilyStrings.newFamilyMembers] : addedMembers} = this.props;
        const newFamilyMembers = addedMembers ? addedMembers[this.familyId] : null;
        let {addNewPatientDialog, listMenuAnchorEl, addType, patientClicked, members, memberIds} = this.state;
        let selectedPatientName = patientClicked && patientClicked.myProfile ? patientClicked.myProfile.lastName : null;
        members = members || [];
        if(newFamilyMembers) members = [...members, ...newFamilyMembers];
        return (
            <div className={classes.root}>
                <Typography paragraph className={classes.familyId}>FAMILY ID : {String(this.familyId).padStart(6, "0")}</Typography>
                <HIRFamilyStatistics
                    familyId={this.familyId}
                    memberIds={memberIds}
                    members={members}/>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        components={[
                            this.refreshButton.bind(this),
                            this.newButton,
                            this.deleteFamilyButton.bind(this),
                            this.saveButton.bind(this),
                        ]}
                        />
                </div>
                <div>
                    <HIRPatientList
                        patients={members}
                        tableProps={{
                            rowAction : this.patientListRowAction.bind(this)
                        }}/>
                    <Menu
                        open={Boolean(listMenuAnchorEl)}
                        anchorEl={listMenuAnchorEl}
                        onClose={()=>this.setState({listMenuAnchorEl : null})}>
                            <MenuItem onClick={this.handlePatientMenuItems("remove")}>Remove {selectedPatientName}</MenuItem>
                            <MenuItem onClick={this.handlePatientMenuItems("view")}>View {selectedPatientName}</MenuItem>
                        </Menu>
                </div>
                <MyDialog
                    open={addNewPatientDialog}
                    close={()=>this.setState({addNewPatientDialog : false, addType : null})}>
                        {addType === "new" ? 
                            <HIRNewPatient
                                createRecord={this.createAndNewPatient.bind(this)}/> : 
                            <HIRFindPatient
                                patientListProps={{
                                    tableProps : {
                                        rowAction : this.handleSelectedPatients.bind(this)
                                    }
                                }}/>
                        }
                    </MyDialog>
            </div>
        );
    }
}


_HIRFamilyView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirFamilyReducer}) => ({
    [hirFamilyStrings.newFamilyMembers] : hirFamilyReducer[hirFamilyStrings.newFamilyMembers]
})


export const HIRFamilyView = connect(mapStateToProps)(withStyles(style)(_HIRFamilyView));
export {HIRFamilyView as default}